import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { NgxUiLoaderService } from 'ngx-ui-loader';
import { AdminService } from 'src/app/_services/admin/admin.service';
import { SearchCountryField, CountryISO, PhoneNumberFormat } from 'ngx-intl-tel-input';
import { MatSnackBar } from '@angular/material/snack-bar';
import { UploadService } from 'src/app/_services/post/upload.service';
import { ConfigService } from 'src/app/_services/config/config.service';
import { MatDialog } from '@angular/material/dialog';
import { ImageModalComponent } from '../assets/image-modal/image-modal.component';

@Component({
  selector: 'app-user-profile',
  templateUrl: './user-profile.component.html',
  styleUrls: ['./user-profile.component.scss']
})
export class UserProfileComponent implements OnInit {
  selectedProfile = '1';
  userProfileFrom: FormGroup;
  userdata;
  initials;
  editView: boolean = false;
  access_token = localStorage.getItem('user_token');
  fileUploads = [];
  imageUploads = [];
  apiUrl;
  user_image_path;
  image_name;
  SearchCountryField = SearchCountryField;
  CountryISO = CountryISO;
  PhoneNumberFormat = PhoneNumberFormat;
  preferredCountries: CountryISO[] = [CountryISO.UnitedStates, CountryISO.UnitedKingdom];

  constructor(public frmbuilder: FormBuilder,
    private adminservices: AdminService,
    private ngxLoader: NgxUiLoaderService,
    private snackBar: MatSnackBar,
    public uploadService: UploadService,
    private config: ConfigService,
    private dialog:MatDialog
  ) {
    this.userdata = JSON.parse(localStorage.getItem('user'));
    this.userProfileFrom = this.frmbuilder.group({
      "firstName": new FormControl(this.userdata.firstName, Validators.required),
      "lastName": new FormControl(this.userdata.lastName, Validators.required),
      "username": new FormControl(this.userdata.username),
      "email": new FormControl(this.userdata.email),
      "userrole": new FormControl(this.userdata.user_role),
      "userstatus": new FormControl(this.userdata.user_status),
      "phone_no": new FormControl(this.userdata.phone_no, [Validators.required])
    })

  }

  ngOnInit(): void {
    this.apiUrl = this.config.apiURL;
    this.image_name = localStorage.getItem('user_profile_img');
    if (this.image_name != 'undefined') {
      this.image_name = JSON.parse(this.image_name);
      this.user_image_path = this.apiUrl + `uploads/user_profile_img/download/${this.image_name}`;
    }else{
      this.user_image_path = null;
    }
    this.initials = this.userdata ? this.userdata.firstName.charAt(0) + this.userdata.lastName.charAt(0) : '';
  }

  SetFormValue(value) {

    this.userProfileFrom.reset();
    this.userProfileFrom.controls["firstName"].setValue(value?.firstName);
    this.userProfileFrom.controls["lastName"].setValue(value?.lastName);
    this.userProfileFrom.controls["username"].setValue(value?.username);
    this.userProfileFrom.controls["email"].setValue(value?.email);
    this.userProfileFrom.controls["userstatus"].setValue(value?.userstatus);
    this.userProfileFrom.controls["userrole"].setValue(value?.userrole);
    this.userProfileFrom.controls["phone_no"].setValue(value?.phone_no);
  }

  showProfile(value) {
    this.selectedProfile = value;
  }

  SaveDetails() {

    this.ngxLoader.start();
    this.adminservices.updateUser(this.userdata.id, this.userProfileFrom.value, this.access_token).subscribe(
      (response) => {
        this.ngxLoader.stop();
        localStorage.setItem('user', JSON.stringify(response));
        this.editView = false;
        this.userdata = JSON.parse(localStorage.getItem('user'));
      },
      (error) => {
        this.ngxLoader.stop();
      })
  }

  onSelectFile(event) {
    if (event.target.files && event.target.files[0]) {
      var filesAmount = event.target.files.length;

      for (let i = 0; i < filesAmount; i++) {
        var reader = new FileReader();
        this.fileUploads.push(event.target.files[i]);
        reader.onload = (readerevent: any) => {

          this.imageUploads.push({ file: readerevent.target.result, type: event.target.files[i].type });
        }
        reader.readAsDataURL(event.target.files[i]);
      }
    }
    if (!((event.target.files[0].type == 'image/png') || (event.target.files[0].type == 'image/jpeg'))) {
      this.snackBar.open("File extension should be .png, .jpg, .jpeg", 'Close', {
        duration: 2000,
        horizontalPosition: 'center',
        verticalPosition: 'bottom',
      });
      return;
    }

    const formData = new FormData();
    for (var i = 0; i < this.fileUploads.length; i++) {
      formData.append("user_profile_img", this.fileUploads[i]);
    }
    this.ngxLoader.start()
    this.uploadService.upload('user_profile_img', formData).subscribe((uploadResponse) => {
      if (uploadResponse) {
        this.fileUploads = [];
        let payload = {
          user_profile_img: uploadResponse.result.files.user_profile_img[0].name
        }
        this.adminservices.updateUser(this.userdata.id, payload, this.access_token).subscribe((response) => {
          if (response) {
            // if (this.userdata.user_profile_img) {
            //   this.uploadService.deleteattachment('user_profile_img', this.userdata.user_profile_img).subscribe((res) => {
            //   })
            // }
            this.user_image_path = this.apiUrl + "uploads/user_profile_img/download/" + response.user_profile_img
            localStorage.setItem('user_profile_img', JSON.stringify(response.user_profile_img));
          }
        })
      }
    }, (error) => {
      this.snackBar.open("Something went wrong!!!", 'Close', {
        duration: 2000,
        horizontalPosition: 'center',
        verticalPosition: 'bottom',
      });
    });
    this.ngxLoader.stop()
  }

  viewImage(link) {
      const src = link
      const dialogRef = this.dialog.open(ImageModalComponent, {
        maxWidth: '100vw',
        maxHeight: '100vh',
        disableClose: true,
        data: {
          'src': src,
          'base64': false
        }
      });
      dialogRef.afterClosed().subscribe(dialogResult => {
      });
    }
}
